#!/usr/bin/env bash
# Materialize the Haskell reference THEORY ECHO for each round-1 target into
# round1/targets/<safe>.hs.txt, using the sanctioned HS oracle only. Run from
# inside the sealed workspace; touches only the HS binary (via pretty_oracle.sh)
# and the corpus .spthy inputs — both permitted materials.
set -u
here=$(cd "$(dirname "$0")" && pwd)
CORPUS="${CORPUS:-/home/kamilner/tamarin-rs/tamarin-prover/examples}"
FLAGS_MAP="${FLAGS_MAP:-/home/kamilner/tamarin-rs/scripts/file_flags.tsv}"
ORACLE="$here/../oracle/pretty_oracle.sh"
mkdir -p "$here/targets"
n=0
while IFS=$'\t' read -r _tags REL; do
  case "$_tags" in \#*|"") continue;; esac
  f="$CORPUS/$REL"
  [ -f "$f" ] || { echo "MISSING $REL" >&2; continue; }
  fl=$(awk -F'\t' -v r="$REL" '!/^#/ && $1==r {print $2}' "$FLAGS_MAP"); fl=${fl//@cd/}
  safe=$(printf '%s' "$REL" | tr '/' '_')
  # pretty_oracle.sh runs HS no-prove and prints the extracted theory echo.
  # shellcheck disable=SC2086
  "$ORACLE" "$f" $fl > "$here/targets/$safe.hs.txt" && n=$((n+1))
done < "$here/families.tsv"
echo "wrote $n HS reference theory-echo blocks to targets/"

1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed), the
3	//! layout engine the reference toolchain (GHC boot library) uses to render
4	//! record-cell term text.
5	//!
6	//! This module implements the `Doc` document model and the combinators, the
7	//! best/fits layout selection, and the `PageMode` renderer, following the
8	//! sanctioned BSD source (`sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/
9	//! Annotated/HughesPJ.hs`) semantics precisely: `<>`/`<+>`, `$$`/`$+$`,
10	//! `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/`hang`, and the
11	//! `best`/`nicest`/`fits` fitting logic with `lineLength` and `ribbonsPerLine`.
12	//!
13	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
14	//! WHICH combinators tamarin applies to a record cell, and with what line width
15	//! / ribbon / indent, is derived from black-box probes and lives in
16	//! [`crate::doclayout`]; this module is the exact engine those parameters feed.
17	//!
18	//! The annotation machinery of the original is elided (this port renders to a
19	//! plain `String`), so `TextBeside` carries the text and its column width
20	//! directly instead of an `AnnotDetails`.
21	//!
22	//! **Evaluation strategy.** The Haskell original relies on lazy evaluation: the
23	//! combinators (`sep`/`fill`/`beside`/`aboveNest`) describe exponentially large
24	//! sets of layouts as union trees, but `best` only ever forces the branches it
25	//! inspects, and `fits` only forces the *first line* of a candidate. A naive
26	//! strict port materializes those whole trees (exponential in the number of
27	//! fill elements). This port mirrors the laziness explicitly: recursive
28	//! combinator continuations are built as [`Doc::Lazy`] thunks (forced on
29	//! demand, memoized), and the `nicest` union choice uses [`fits_ahead`], which
30	//! decides `fits (min w r - sl) (best' ...)` by walking the *unresolved*
31	//! branch's first line only. Both are pure evaluation-order mirrors of the
32	//! sanctioned semantics: the resolved layout is byte-identical.
33	
34	use std::cell::RefCell;
35	use std::rc::Rc;
36	
37	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
38	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
39	/// constructors (annotations elided).
40	#[derive(Clone, Debug)]
41	pub enum Doc {
42	    /// An empty span (`empty`): no height, no width.
43	    Empty,
44	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
45	    NilAbove(Rc<Doc>),
46	    /// `text s <> x` — literal text (with its column width) beside `x`. The
47	    /// argument is never a `Nest`.
48	    TextBeside(Rc<str>, usize, Rc<Doc>),
49	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
50	    Nest(isize, Rc<Doc>),
51	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
52	    Union(Rc<Doc>, Rc<Doc>),
53	    /// The empty *set* of documents.
54	    NoDoc,
55	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
56	    Beside(Rc<Doc>, bool, Rc<Doc>),
57	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
58	    Above(Rc<Doc>, bool, Rc<Doc>),
59	    /// A suspended sub-document (the strict mirror of a Haskell thunk):
60	    /// computed on first [`force`], then memoized. Only ever wraps an already
61	    /// *reduced* document (an RDoc — no `Beside`/`Above`).
62	    Lazy(Rc<LazyDoc>),
63	}
64	
65	/// The shared state of a [`Doc::Lazy`] thunk.
66	pub struct LazyDoc(RefCell<LazyState>);
67	
68	enum LazyState {
69	    Pending(Option<Box<dyn FnOnce() -> Doc>>),
70	    Forced(Doc),
71	}
72	
73	impl std::fmt::Debug for LazyDoc {
74	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
75	        match &*self.0.borrow() {
76	            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
77	            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
78	        }
79	    }
80	}
81	
82	use Doc::*;
83	
84	fn rc(d: Doc) -> Rc<Doc> {
85	    Rc::new(d)
86	}
87	
88	/// Suspend a document computation (a thunk). The closure runs at most once.
89	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
90	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
91	        Box::new(f),
92	    ))))))
93	}
94	
95	/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
96	/// children stay shared via `Rc`). Thunks are computed once and memoized;
97	/// chains of thunks collapse to the final value.
98	fn force(d: &Doc) -> Doc {
99	    match d {
100	        Lazy(l) => {
101	            if let LazyState::Forced(v) = &*l.0.borrow() {
102	                return v.clone();
103	            }
104	            let f = match &mut *l.0.borrow_mut() {
105	                LazyState::Pending(f) => f.take().expect("re-entrant force"),
106	                LazyState::Forced(v) => return v.clone(),
107	            };
108	            let v = force(&f());
109	            *l.0.borrow_mut() = LazyState::Forced(v.clone());
110	            v
111	        }
112	        _ => d.clone(),
113	    }
114	}
115	
116	// ---------------------------------------------------------------------------
117	// Constructors (§ "Values and Predicates")
118	
119	/// A one-character document.
120	pub fn char(c: char) -> Doc {
121	    let mut buf = [0u8; 4];
122	    let s: &str = c.encode_utf8(&mut buf);
123	    TextBeside(Rc::from(s), 1, rc(Empty))
124	}
125	
126	/// A one-line literal string document; its width is its Unicode-scalar count.
127	pub fn text(s: &str) -> Doc {
128	    let len = s.chars().count();
129	    TextBeside(Rc::from(s), len, rc(Empty))
130	}
131	
132	/// Text with an explicit column width (`sizedText l s`); use width 0 for
133	/// non-printing text.
134	pub fn sized_text(len: usize, s: &str) -> Doc {
135	    TextBeside(Rc::from(s), len, rc(Empty))
136	}
137	
138	/// The empty document (identity for `<>`, `$$`, and list combinators).
139	pub fn empty() -> Doc {
140	    Empty
141	}
142	
143	/// Is this the empty document?
144	pub fn is_empty(d: &Doc) -> bool {
145	    matches!(force(d), Empty)
146	}
147	
148	
149	// ---------------------------------------------------------------------------
150	// Structural smart-constructors
151	
152	fn nil_above_(d: Rc<Doc>) -> Doc {
153	    NilAbove(d)
154	}
155	
156	fn text_beside_(s: Rc<str>, l: usize, d: Rc<Doc>) -> Doc {
157	    TextBeside(s, l, d)
158	}
159	
160	fn nest_(k: isize, d: Rc<Doc>) -> Doc {
161	    Nest(k, d)
162	}
163	
164	fn union_(a: Rc<Doc>, b: Rc<Doc>) -> Doc {
165	    Union(a, b)
166	}
167	
168	/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
169	pub fn reduce_doc(d: &Doc) -> Doc {
170	    match d {
171	        Beside(p, g, q) => beside(p, *g, &reduce_doc(q)),
172	        Above(p, g, q) => above(p, *g, &reduce_doc(q)),
173	        other => other.clone(),
174	    }
175	}
176	
177	// ---------------------------------------------------------------------------
178	// nest / mkNest / mkUnion
179	
180	/// `nest k p` — indent by `k` (may be negative).
181	pub fn nest(k: isize, p: &Doc) -> Doc {
182	    mk_nest(k, &reduce_doc(p))
183	}
184	
185	fn mk_nest(k: isize, d: &Doc) -> Doc {
186	    let df = force(d);
187	    match &df {
188	        Nest(k1, p) => mk_nest(k + k1, p),
189	        NoDoc => NoDoc,
190	        Empty => Empty,
191	        _ if k == 0 => df,
192	        _ => nest_(k, rc(df)),
193	    }
194	}
195	
196	fn mk_union(p: Doc, q: Doc) -> Doc {
197	    match force(&p) {
198	        Empty => Empty,
199	        pf => union_(rc(pf), rc(q)),
200	    }
201	}
202	
203	// ---------------------------------------------------------------------------
204	// Horizontal composition <> and <+>
205	
206	/// `p <> q` — beside.
207	pub fn beside_op(p: Doc, q: Doc) -> Doc {
208	    beside_(p, false, q)
209	}
210	
211	/// `p <+> q` — beside, separated by a space unless an argument is empty.
212	pub fn beside_space(p: Doc, q: Doc) -> Doc {
213	    beside_(p, true, q)
214	}
215	
216	fn beside_(p: Doc, g: bool, q: Doc) -> Doc {
217	    match (&p, &q) {
218	        (_, Empty) => p,
219	        (Empty, _) => q,
220	        _ => Beside(rc(p), g, rc(q)),
221	    }
222	}
223	
224	/// `beside p g q` (spec: `p <g> q`) over reduced docs. Union branches and the
225	/// text-tail continuation are suspended ([`lazy`]), mirroring the sanctioned
226	/// source's (non-`$!`) laziness.
227	fn beside(p: &Doc, g: bool, q: &Doc) -> Doc {
228	    let pf = force(p);
229	    match &pf {
230	        NoDoc => NoDoc,
231	        Union(p1, p2) => {
232	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
233	            union_(
234	                rc(lazy(move || beside(&p1, g, &qa))),
235	                rc(lazy(move || beside(&p2, g, &qb))),
236	            )
237	        }
238	        Empty => q.clone(),
239	        Nest(k, p1) => nest_(*k, rc(beside(p1, g, q))),
240	        Beside(p1, g1, q1) => {
241	            if *g1 == g {
242	                beside(p1, *g1, &beside(q1, g, q))
243	            } else {
244	                beside(&reduce_doc(&pf), g, q)
245	            }
246	        }
247	        Above(..) => beside(&reduce_doc(&pf), g, q),
248	        NilAbove(p1) => nil_above_(rc(beside(p1, g, q))),
249	        TextBeside(s, l, p1) => {
250	            let (p1, q1) = (p1.clone(), q.clone());
251	            let rest = lazy(move || match force(&p1) {
252	                Empty => nil_beside(g, &q1),
253	                _ => beside(&p1, g, &q1),
254	            });
255	            text_beside_(s.clone(), *l, rc(rest))
256	        }
257	        Lazy(_) => unreachable!("beside: forced doc"),
258	    }
259	}
260	
261	/// `nilBeside g p` (spec: `text "" <g> p`).
262	fn nil_beside(g: bool, p: &Doc) -> Doc {
263	    let pf = force(p);
264	    match &pf {
265	        Empty => Empty,
266	        Nest(_, p1) => nil_beside(g, p1),
267	        _ => {
268	            if g {
269	                TextBeside(Rc::from(" "), 1, rc(pf))
270	            } else {
271	                pf
272	            }
273	        }
274	    }
275	}
276	
277	// ---------------------------------------------------------------------------
278	// Vertical composition $$ and $+$
279	
280	/// `p $$ q` — above, with overlap allowed.
281	pub fn above_op(p: Doc, q: Doc) -> Doc {
282	    above_(p, false, q)
283	}
284	
285	/// `p $+$ q` — above, no overlap.
286	pub fn above_plus(p: Doc, q: Doc) -> Doc {
287	    above_(p, true, q)
288	}
289	
290	fn above_(p: Doc, g: bool, q: Doc) -> Doc {
291	    match (&p, &q) {
292	        (_, Empty) => p,
293	        (Empty, _) => q,
294	        _ => Above(rc(p), g, rc(q)),
295	    }
296	}
297	
298	fn above(p: &Doc, g: bool, q: &Doc) -> Doc {
299	    let pf = force(p);
300	    match &pf {
301	        Above(p1, g1, q1) => above(p1, *g1, &above(q1, g, q)),
302	        Beside(..) => above_nest(&reduce_doc(&pf), g, 0, &reduce_doc(q)),
303	        _ => above_nest(&pf, g, 0, &reduce_doc(q)),
304	    }
305	}
306	
307	/// `aboveNest p g k q` (spec: `p $g$ (nest k q)`). Union branches and the
308	/// recursive continuations are suspended, mirroring the sanctioned laziness.
309	fn above_nest(p: &Doc, g: bool, k: isize, q: &Doc) -> Doc {
310	    let pf = force(p);
311	    match &pf {
312	        NoDoc => NoDoc,
313	        Union(p1, p2) => {
314	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
315	            union_(
316	                rc(lazy(move || above_nest(&p1, g, k, &qa))),
317	                rc(lazy(move || above_nest(&p2, g, k, &qb))),
318	            )
319	        }
320	        Empty => mk_nest(k, q),
321	        Nest(k1, p1) => {
322	            let (k1, p1, q1) = (*k1, p1.clone(), q.clone());
323	            nest_(k1, rc(lazy(move || above_nest(&p1, g, k - k1, &q1))))
324	        }
325	        NilAbove(p1) => {
326	            let (p1, q1) = (p1.clone(), q.clone());
327	            nil_above_(rc(lazy(move || above_nest(&p1, g, k, &q1))))
328	        }
329	        TextBeside(s, l, p1) => {
330	            let k1 = k - (*l as isize);
331	            let (p1, q1) = (p1.clone(), q.clone());
332	            let rest = lazy(move || match force(&p1) {
333	                Empty => nil_above_nest(g, k1, &q1),
334	                _ => above_nest(&p1, g, k1, &q1),
335	            });
336	            text_beside_(s.clone(), *l, rc(rest))
337	        }
338	        Above(..) => panic!("aboveNest Above"),
339	        Beside(..) => panic!("aboveNest Beside"),
340	        Lazy(_) => unreachable!("aboveNest: forced doc"),
341	    }
342	}
343	
344	/// `nilAboveNest g k q` (spec: `text s <> (text "" $g$ nest k q)`).
345	fn nil_above_nest(g: bool, k: isize, q: &Doc) -> Doc {
346	    let qf = force(q);
347	    match &qf {
348	        Empty => Empty,
349	        Nest(k1, q1) => nil_above_nest(g, k + k1, q1),
350	        _ => {
351	            if !g && k > 0 {
352	                let ind = indent(k);
353	                let len = ind.chars().count();
354	                text_beside_(Rc::from(ind.as_str()), len, rc(qf))
355	            } else {
356	                nil_above_(rc(mk_nest(k, &qf)))
357	            }
358	        }
359	    }
360	}
361	
362	// ---------------------------------------------------------------------------
363	// List versions: hcat / hsep / vcat  (via reduceHoriz/reduceVert)
364	
365	#[derive(Clone, Copy)]
366	enum IsEmpty {
367	    // `Empty` mirrors the Haskell `reduceHoriz`/`reduceVert` return type; this
368	    // strict port only ever yields `NotEmpty`, but the variant is kept to match
369	    // the sanctioned source's shape.
370	    #[allow(dead_code)]
371	    Empty,
372	    NotEmpty,
373	}
374	
375	fn reduce_horiz(d: &Doc) -> (IsEmpty, Doc) {
376	    match d {
377	        Beside(p, g, q) => {
378	            let (_, pr) = reduce_horiz(p);
379	            eliminate_empty(true, pr, *g, reduce_horiz(q))
380	        }
381	        _ => (IsEmpty::NotEmpty, d.clone()),
382	    }
383	}
384	
385	fn reduce_vert(d: &Doc) -> (IsEmpty, Doc) {
386	    match d {
387	        Above(p, g, q) => {
388	            let (_, pr) = reduce_vert(p);
389	            eliminate_empty(false, pr, *g, reduce_vert(q))
390	        }
391	        _ => (IsEmpty::NotEmpty, d.clone()),
392	    }
393	}
394	
395	/// `beside_cons` = true builds `Beside`, false builds `Above`.
396	fn eliminate_empty(beside_cons: bool, p: Doc, g: bool, q: (IsEmpty, Doc)) -> (IsEmpty, Doc) {
397	    match p {
398	        Empty => q,
399	        _ => {
400	            let out = match q {
401	                (IsEmpty::NotEmpty, q1) => {
402	                    if beside_cons {
403	                        Beside(rc(p), g, rc(q1))
404	                    } else {
405	                        Above(rc(p), g, rc(q1))
406	                    }
407	                }
408	                (IsEmpty::Empty, _) => p,
409	            };
410	            (IsEmpty::NotEmpty, out)
411	        }
412	    }
413	}
