447	/// `punctuate p [d1,…,dn] = [d1<>p, …, d(n-1)<>p, dn]`.
448	pub fn punctuate(p: &Doc, ds: Vec<Doc>) -> Vec<Doc> {
449	    let n = ds.len();
450	    ds.into_iter()
451	        .enumerate()
452	        .map(|(i, d)| {
453	            if i + 1 < n {
454	                beside_op(d, p.clone())
455	            } else {
456	                d
457	            }
458	        })
459	        .collect()
460	}
