463	// sep / cat
464	
465	/// `sep` — either `hsep` (one line) or `vcat`.
466	pub fn sep(ds: Vec<Doc>) -> Doc {
467	    sep_x(true, ds)
468	}
469	
470	/// `cat` — either `hcat` (one line) or `vcat`.
471	pub fn cat(ds: Vec<Doc>) -> Doc {
472	    sep_x(false, ds)
473	}
474	
475	fn sep_x(x: bool, ds: Vec<Doc>) -> Doc {
476	    if ds.is_empty() {
477	        return Empty;
478	    }
479	    let mut it = ds.into_iter();
480	    let p = it.next().unwrap();
481	    let ys: Vec<Doc> = it.collect();
482	    sep1(x, &reduce_doc(&p), 0, &ys)
483	}
484	
485	fn sep1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
486	    let pf = force(p);
487	    match &pf {
488	        NoDoc => NoDoc,
489	        Union(p1, q) => {
490	            let (p1, q) = (p1.clone(), q.clone());
491	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
492	            union_(
493	                rc(lazy(move || sep1(g, &p1, k, &ya))),
494	                rc(lazy(move || {
495	                    above_nest(&q, false, k, &reduce_doc(&vcat(yb)))
496	                })),
497	            )
498	        }
499	        Empty => mk_nest(k, &sep_x(g, ys.to_vec())),
500	        Nest(n, p1) => {
501	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
502	            nest_(n, rc(lazy(move || sep1(g, &p1, k - n, &ys))))
503	        }
504	        NilAbove(p1) => {
505	            let (p1, ys) = (p1.clone(), ys.to_vec());
506	            nil_above_(rc(lazy(move || {
507	                above_nest(&p1, false, k, &reduce_doc(&vcat(ys)))
508	            })))
509	        }
510	        TextBeside(s, l, p1) => {
511	            let li = *l as isize;
512	            let (p1, ys) = (p1.clone(), ys.to_vec());
513	            text_beside_(
514	                s.clone(),
515	                *l,
516	                rc(lazy(move || sep_nb(g, &p1, k - li, &ys))),
517	            )
518	        }
519	        Above(..) => panic!("sep1 Above"),
520	        Beside(..) => panic!("sep1 Beside"),
521	        Lazy(_) => unreachable!("sep1: forced doc"),
522	    }
523	}
524	
525	fn sep_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
526	    let pf = force(p);
527	    match &pf {
528	        Nest(_, p1) => sep_nb(g, p1, k, ys),
529	        Empty => {
530	            let rest = if g {
531	                hsep(ys.to_vec())
532	            } else {
533	                hcat(ys.to_vec())
534	            };
535	            let left = one_liner(&nil_beside(g, &reduce_doc(&rest)));
536	            let (k1, ys1) = (k, ys.to_vec());
537	            let right = lazy(move || nil_above_nest(false, k1, &reduce_doc(&vcat(ys1))));
538	            mk_union(left, right)
539	        }
540	        _ => sep1(g, &pf, k, ys),
541	    }
542	}
