557	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
558	    if ds.is_empty() {
559	        return Empty;
560	    }
561	    let mut it = ds.into_iter();
562	    let p = it.next().unwrap();
563	    let ys: Vec<Doc> = it.collect();
564	    fill1(g, &reduce_doc(&p), 0, &ys)
565	}
566	
567	fn fill1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
568	    let pf = force(p);
569	    match &pf {
570	        NoDoc => NoDoc,
571	        Union(p1, q) => {
572	            let (p1, q) = (p1.clone(), q.clone());
573	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
574	            union_(
575	                rc(lazy(move || fill1(g, &p1, k, &ya))),
576	                rc(lazy(move || above_nest(&q, false, k, &fill(g, yb)))),
577	            )
578	        }
579	        Empty => mk_nest(k, &fill(g, ys.to_vec())),
580	        Nest(n, p1) => {
581	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
582	            nest_(n, rc(lazy(move || fill1(g, &p1, k - n, &ys))))
583	        }
584	        NilAbove(p1) => {
585	            let (p1, ys) = (p1.clone(), ys.to_vec());
586	            nil_above_(rc(lazy(move || {
587	                above_nest(&p1, false, k, &fill(g, ys))
588	            })))
589	        }
590	        TextBeside(s, l, p1) => {
591	            let li = *l as isize;
592	            let (p1, ys) = (p1.clone(), ys.to_vec());
593	            text_beside_(
594	                s.clone(),
595	                *l,
596	                rc(lazy(move || fill_nb(g, &p1, k - li, &ys))),
597	            )
598	        }
599	        Above(..) => panic!("fill1 Above"),
600	        Beside(..) => panic!("fill1 Beside"),
601	        Lazy(_) => unreachable!("fill1: forced doc"),
602	    }
603	}
604	
605	fn fill_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
606	    let pf = force(p);
607	    match &pf {
608	        Nest(_, p1) => fill_nb(g, p1, k, ys),
609	        Empty => {
610	            if ys.is_empty() {
611	                Empty
612	            } else if matches!(force(&ys[0]), Empty) {
613	                fill_nb(g, &Empty, k, &ys[1..])
614	            } else {
615	                fill_nbe(g, k, &ys[0], &ys[1..])
616	            }
617	        }
618	        _ => fill1(g, &pf, k, ys),
619	    }
620	}
621	
622	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
623	    let k1 = if g { k - 1 } else { k };
624	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
625	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
626	    let (y2, ys2) = (y.clone(), ys.to_vec());
627	    let right = lazy(move || {
628	        let mut rest = vec![y2];
629	        rest.extend(ys2);
630	        nil_above_nest(false, k, &fill(g, rest))
631	    });
632	    mk_union(left, right)
633	}
634	
635	fn elide_nest(d: &Doc) -> Doc {
636	    let df = force(d);
637	    match &df {
638	        Nest(_, d1) => d1.as_ref().clone(),
639	        _ => df,
640	    }
641	}
