643	// ---------------------------------------------------------------------------
644	// Best layout: best / nicest / fits / oneLiner
645	
646	fn one_liner(d: &Doc) -> Doc {
647	    let df = force(d);
648	    match &df {
649	        NoDoc => NoDoc,
650	        Empty => Empty,
651	        NilAbove(_) => NoDoc,
652	        TextBeside(s, l, p) => {
653	            let p = p.clone();
654	            text_beside_(s.clone(), *l, rc(lazy(move || one_liner(&p))))
655	        }
656	        Nest(k, p) => {
657	            let (k, p) = (*k, p.clone());
658	            nest_(k, rc(lazy(move || one_liner(&p))))
659	        }
660	        Union(p, _) => one_liner(p),
661	        Above(..) => panic!("oneLiner Above"),
662	        Beside(..) => panic!("oneLiner Beside"),
663	        Lazy(_) => unreachable!("oneLiner: forced doc"),
664	    }
665	}
666	
667	/// `best w r doc` — resolve unions to a single layout for line width `w`,
668	/// ribbon width `r`. Mirrors the Haskell `best`/`nicest1` including its
669	/// laziness: the resolved document's tails are thunks, so `fits` (which only
670	/// inspects a candidate's *first line*) never forces a branch beyond that
671	/// line, and the right branch of a union is only resolved when the left's
672	/// first line does not fit.
673	fn best(w: isize, r: isize, d: &Doc) -> Doc {
674	    get(w, r, d)
675	}
676	
677	fn get(w: isize, r: isize, d: &Doc) -> Doc {
678	    let df = force(d);
679	    match &df {
680	        Empty => Empty,
681	        NoDoc => NoDoc,
682	        NilAbove(p) => {
683	            let p = p.clone();
684	            nil_above_(rc(lazy(move || get(w, r, &p))))
685	        }
686	        TextBeside(s, l, p) => {
687	            let (li, p) = (*l as isize, p.clone());
688	            text_beside_(s.clone(), *l, rc(lazy(move || get1(w, r, li, &p))))
689	        }
690	        Nest(k, p) => {
691	            let (k, p) = (*k, p.clone());
692	            nest_(k, rc(lazy(move || get(w - k, r, &p))))
693	        }
694	        Union(p, q) => nicest(w, r, p, q),
695	        Above(..) => panic!("best get Above"),
696	        Beside(..) => panic!("best get Beside"),
697	        Lazy(_) => unreachable!("get: forced doc"),
698	    }
699	}
700	
701	fn get1(w: isize, r: isize, sl: isize, d: &Doc) -> Doc {
702	    let df = force(d);
703	    match &df {
704	        Empty => Empty,
705	        NoDoc => NoDoc,
706	        NilAbove(p) => {
707	            let p = p.clone();
708	            nil_above_(rc(lazy(move || get(w - sl, r, &p))))
709	        }
710	        TextBeside(s, l, p) => {
711	            let (li, p) = (*l as isize, p.clone());
712	            text_beside_(
713	                s.clone(),
714	                *l,
715	                rc(lazy(move || get1(w, r, sl + li, &p))),
716	            )
717	        }
718	        Nest(_, p) => get1(w, r, sl, p),
719	        Union(p, q) => nicest1(w, r, sl, p, q),
720	        Above(..) => panic!("best get1 Above"),
721	        Beside(..) => panic!("best get1 Beside"),
722	        Lazy(_) => unreachable!("get1: forced doc"),
723	    }
724	}
725	
726	fn nicest(w: isize, r: isize, p: &Doc, q: &Doc) -> Doc {
727	    nicest1(w, r, 0, p, q)
728	}
729	
730	fn nicest1(w: isize, r: isize, sl: isize, p: &Doc, q: &Doc) -> Doc {
731	    // Resolve the left branch lazily; keep it iff its first line fits (`fits`
732	    // forces only that first line). Resolve the right branch only otherwise.
733	    let (pc, qc) = (p.clone(), q.clone());
734	    let lp = lazy(move || get1(w, r, sl, &pc));
735	    if fits(w.min(r) - sl, &lp) {
736	        lp
737	    } else {
738	        lazy(move || get1(w, r, sl, &qc))
739	    }
740	}
741	
742	/// True iff the *first line* of `d` fits in `n` columns. Forces only up to the
743	/// first line break of an already-`best`-resolved (thunked) document.
744	fn fits(n: isize, d: &Doc) -> bool {
745	    if n < 0 {
746	        return false;
747	    }
748	    match &force(d) {
749	        NoDoc => false,
750	        Empty => true,
751	        NilAbove(_) => true,
752	        TextBeside(_, l, p) => fits(n - *l as isize, p),
753	        Above(..) => panic!("fits Above"),
754	        Beside(..) => panic!("fits Beside"),
755	        Union(..) => panic!("fits Union"),
756	        Nest(..) => panic!("fits Nest"),
757	        Lazy(_) => unreachable!("fits: forced doc"),
758	    }
759	}
