763	
764	fn indent(n: isize) -> String {
765	    if n <= 0 {
766	        String::new()
767	    } else {
768	        " ".repeat(n as usize)
769	    }
770	}
771	
772	/// Banker's-rounding of `line_len / ribbons` to match Haskell `round`.
773	fn round_ribbon(line_len: isize, ribbons: f64) -> isize {
774	    let v = line_len as f64 / ribbons;
775	    let floor = v.floor();
776	    let diff = v - floor;
777	    let rounded = if (diff - 0.5).abs() < 1e-9 {
778	        // round half to even
779	        let f = floor as i64;
780	        if f % 2 == 0 {
781	            f
782	        } else {
783	            f + 1
784	        }
785	    } else {
786	        v.round() as i64
787	    };
788	    rounded as isize
789	}
790	
791	/// Render a document in `PageMode` at line length `line_len` and
792	/// `ribbons_per_line`, producing the plain string (newline-separated lines,
793	/// each continuation prefixed by its indentation spaces).
794	pub fn render_page(line_len: isize, ribbons_per_line: f64, doc: &Doc) -> String {
795	    let ribbon_len = round_ribbon(line_len, ribbons_per_line);
796	    let reduced = reduce_doc(doc);
797	    let best_doc = best(line_len, ribbon_len, &reduced);
798	    display_page(line_len, ribbon_len, &best_doc)
799	}
800	
801	fn display_page(page_width: isize, ribbon_width: isize, doc: &Doc) -> String {
802	    let _gap = page_width - ribbon_width;
803	    let mut out = String::new();
804	    lay(&mut out, 0, doc);
805	    out
806	}
807	
808	fn lay(out: &mut String, k: isize, d: &Doc) {
809	    match &force(d) {
810	        Nest(k1, p) => lay(out, k + k1, p),
811	        Empty => {}
812	        NilAbove(p) => {
813	            out.push('\n');
814	            lay(out, k, p);
815	        }
816	        TextBeside(s, l, p) => lay1(out, k, s, *l, p),
817	        Above(..) => panic!("display lay Above"),
818	        Beside(..) => panic!("display lay Beside"),
819	        NoDoc => panic!("display lay NoDoc"),
820	        Union(..) => panic!("display lay Union"),
821	        Lazy(_) => unreachable!("lay: forced doc"),
822	    }
823	}
824	
825	fn lay1(out: &mut String, k: isize, s: &str, l: usize, p: &Doc) {
826	    out.push_str(&indent(k));
827	    out.push_str(s);
828	    lay2(out, k + l as isize, p);
829	}
830	
831	fn lay2(out: &mut String, k: isize, d: &Doc) {
832	    match &force(d) {
833	        NilAbove(p) => {
834	            out.push('\n');
835	            lay(out, k, p);
836	        }
837	        TextBeside(s, l, p) => {
838	            out.push_str(s);
839	            lay2(out, k + *l as isize, p);
840	        }
841	        Nest(_, p) => lay2(out, k, p),
842	        Empty => {}
843	        Above(..) => panic!("display lay2 Above"),
844	        Beside(..) => panic!("display lay2 Beside"),
845	        NoDoc => panic!("display lay2 NoDoc"),
846	        Union(..) => panic!("display lay2 Union"),
847	        Lazy(_) => unreachable!("lay2: forced doc"),
848	    }
849	}
