//! Minimal AST subset the renderer consumes.
//!
//! This is the clean crate's OWN model, shaped to stay drop-in compatible with
//! the integration surface in `../../interface/ast_types.rs` (same variant
//! names and field meanings) while only carrying what the R1 renderer needs.
//! Behavior is driven by the oracle (see workspace/BEHAVIOR.md), not by that
//! header.
//!
//! R2–R4 types are placeholders — flesh them out at those sub-targets.

// ── R1: terms (the deep core) ───────────────────────────────────────────────

/// Multiset-rewriting term. Rendered by `term::render`.
#[derive(Debug, Clone, PartialEq)]
pub enum Term {
    Var(VarSpec),
    /// Public string constant; renders quoted: `'name'`.
    PubLit(String),
    /// Fresh name constant; renders `~'name'`.
    FreshLit(String),
    /// Natural-number literal, digits only; renders `%digits`.
    NatLit(String),
    /// Natural-number literal; renders `%n`.
    Number(u64),
    /// The DH multiplicative unit; renders `one`.
    NumberOne,
    /// The natural-number one; renders `%1`.
    NatOne,
    /// The DH group neutral element; renders `DH_neutral`.
    DhNeutral,
    /// Function application `f(a, b, …)`; arity 0 renders bare (`f`).
    App(String, Vec<Term>),
    /// Named binary algebra operator; `"exp"` renders infix `a^b`, anything
    /// else falls back to application form.
    AlgApp(String, Box<Term>, Box<Term>),
    /// Tuple `<a, b, c>`; a Pair in LAST position flattens into the enclosing
    /// tuple, a Pair in any other position keeps its own delimiters.
    Pair(Vec<Term>),
    /// Bi-system term `diff(l, r)`; renders in application form.
    Diff(Box<Term>, Box<Term>),
    BinOp(BinOp, Box<Term>, Box<Term>),
    /// Sapic pattern-match marker (`=t`). UNOBSERVABLE through the no-prove
    /// MSR echo — see BEHAVIOR.md; the rendering here is a flagged
    /// placeholder, not oracle-pinned.
    PatMatch(Box<Term>),
}

/// Infix operators. Glyphs and parenthesization per BEHAVIOR.md: `Exp`
/// renders `a^b` with flat chains and no added parens; the four AC operators
/// render `(a<op>b<op>c)` — self-parenthesized, flattened, no spaces.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum BinOp {
    Exp,     // ^
    Mult,    // *
    Union,   // ++
    Xor,     // ⊕ (U+2295)
    NatPlus, // %+
}

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct VarSpec {
    pub name: String,
    /// Rendered as a `.idx` suffix when > 0 (`x.1`, `~x.7`).
    pub idx: u64,
    pub sort: SortHint,
    /// Source-level type annotation; not rendered in the theory echo.
    pub typ: Option<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Default)]
pub enum SortHint {
    Msg,
    Pub,   // $x
    Fresh, // ~x
    Node,  // #i
    Nat,   // %n
    /// Source-suffix form (`x:pub`); the echo always shows the sigil form,
    /// so this renders identically to the corresponding sigil sort.
    Suffix(SuffixSort),
    #[default]
    Untagged,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SuffixSort {
    Msg,
    Pub,
    Fresh,
    Node,
    Nat,
}

// ── R1: signature block ─────────────────────────────────────────────────────

/// The DECLARED signature to render as `builtins:` / `functions:` /
/// `equations:`. The renderer itself performs the observable closure: builtin
/// expansion into function/equation entries, canonical builtin ordering,
/// dedup, and sorting (all oracle-pinned — BEHAVIOR.md "Signature section").
#[derive(Debug, Clone, PartialEq, Default)]
pub struct Signature {
    /// Builtin names as declared (`"diffie-hellman"`, `"hashing"`, …).
    pub builtins: Vec<String>,
    /// User-declared function symbols.
    pub functions: Vec<FunctionDecl>,
    /// User-declared equations.
    pub equations: Vec<Equation>,
    /// True when the user equation block carries `[convergent]`.
    pub convergent: bool,
}

#[derive(Debug, Clone, PartialEq)]
pub struct FunctionDecl {
    pub name: String,
    pub arity: usize,
    pub private: bool,
    pub destructor: bool,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Equation {
    pub lhs: Term,
    pub rhs: Term,
}

// ── R2: facts & rules (placeholders — flesh out at R2) ──────────────────────

#[derive(Debug, Clone, PartialEq)]
pub struct Fact {
    pub persistent: bool, // `!Name`
    pub name: String,
    pub args: Vec<Term>,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Rule {
    pub name: String,
    pub premises: Vec<Fact>,
    pub actions: Vec<Fact>,
    pub conclusions: Vec<Fact>,
}

/// Pre-computed AC-variant substitutions for a rule (from the ported solver);
/// the `variants (modulo AC)` block text renders from this. Shape TBD at R2.
#[derive(Debug, Clone, PartialEq, Default)]
pub struct AcVariants;

// ── R3: formulas, restrictions, lemmas (placeholders — flesh out at R3) ─────

#[derive(Debug, Clone, PartialEq)]
pub enum Formula {
    False,
    True,
    Atom(Atom),
    Not(Box<Formula>),
    And(Box<Formula>, Box<Formula>),
    Or(Box<Formula>, Box<Formula>),
    Implies(Box<Formula>, Box<Formula>),
    Iff(Box<Formula>, Box<Formula>),
    Forall(Vec<VarSpec>, Box<Formula>),
    Exists(Vec<VarSpec>, Box<Formula>),
}

#[derive(Debug, Clone, PartialEq)]
pub enum Atom {
    Eq(Term, Term),
    Less(Term, Term),
    Subterm(Term, Term),
    Action(Fact, Term), // Fact @ #i
    Last(Term),
    Pred(Fact),
}

#[derive(Debug, Clone, PartialEq)]
pub struct Restriction {
    pub name: String,
    pub formula: Formula,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Lemma {
    pub name: String,
    pub exists_trace: bool,
    pub formula: Formula,
}

/// Pre-computed guarded-formula negation shown in the `/* guarded formula
/// characterizing all counter-examples */` comment (from the ported guarded
/// transform). Shape TBD at R3.
#[derive(Debug, Clone, PartialEq, Default)]
pub struct Guarded;

// ── R4: macros / predicates ─────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
pub struct Macro {
    pub name: String,
    pub params: Vec<Term>,
    pub body: Term,
}

#[derive(Debug, Clone, PartialEq)]
pub struct Predicate {
    pub name: String,
    pub params: Vec<VarSpec>,
    pub body: Formula,
}

// ── top-level theory ────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq, Default)]
pub struct Theory {
    pub name: String,
    pub items: Vec<TheoryItem>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum TheoryItem {
    Macros(Vec<Macro>),
    Predicates(Vec<Predicate>),
    Rule(Rule),
    Restriction(Restriction),
    Lemma(Lemma),
    FormalComment { header: String, body: String },
}

//! R1 — TERM rendering (the deep core; every other sub-target reuses this).
//!
//! Every glyph, spacing and parenthesization rule here is oracle-pinned; see
//! workspace/BEHAVIOR.md "Term rendering" for the probe provenance of each
//! case. Summary of the observed surface:
//!
//!   * sort sigils `~ $ # %` + `.idx` suffix when the index is > 0;
//!   * public constants `'name'`, fresh constants `~'name'`, naturals `%n`,
//!     DH constants `one` / `DH_neutral`;
//!   * application `f(a, b)` — comma attached to the preceding argument, fill
//!     space between arguments, wrap aligned after `(`; arity 0 renders bare;
//!   * tuples `<a, b, c>` — `", "` attached to each element (a wrapped line
//!     keeps the trailing space), right-nested pairs flattened;
//!   * `^` chains render flat for BOTH association orders, no parens added;
//!   * AC operators `*`, `⊕`, `++`, `%+` — self-parenthesized `(a*b*c)`,
//!     flattened across both sides, no spaces, break between elements with
//!     the operator attached to the preceding element;
//!   * `diff(l, r)` in application form.

use crate::ast::{BinOp, SortHint, SuffixSort, Term, VarSpec};
use crate::doc::{
    beside_op, char, fcat, fsep, punctuate, render_with, text, Doc,
};

/// Theory-echo layout parameters (SPEC; every wrap observation in
/// BEHAVIOR.md reproduces at these settings).
pub(crate) const WIDTH: isize = 110;
pub(crate) const RIBBON: isize = 73;

/// Render one term at the echo's layout parameters, starting at column 0.
pub fn render(t: &Term) -> String {
    render_with(WIDTH, RIBBON, &doc(t))
}

/// The term's `Doc` (embedded by the signature/rule/formula renderers).
pub(crate) fn doc(t: &Term) -> Doc {
    match t {
        Term::Var(v) => text(&var_str(v)),
        Term::PubLit(s) => text(&format!("'{s}'")),
        Term::FreshLit(s) => text(&format!("~'{s}'")),
        Term::NatLit(s) => text(&format!("%{s}")),
        Term::Number(n) => text(&format!("%{n}")),
        Term::NumberOne => text("one"),
        Term::NatOne => text("%1"),
        Term::DhNeutral => text("DH_neutral"),
        Term::App(f, args) => {
            if args.is_empty() {
                text(f)
            } else {
                app_doc(f, args)
            }
        }
        Term::AlgApp(name, a, b) => {
            if name == "exp" {
                exp_doc(t)
            } else {
                app_doc(name, &[(**a).clone(), (**b).clone()])
            }
        }
        Term::Pair(elems) => pair_doc(elems),
        Term::Diff(l, r) => app_doc("diff", &[(**l).clone(), (**r).clone()]),
        Term::BinOp(BinOp::Exp, _, _) => exp_doc(t),
        Term::BinOp(op, _, _) => ac_doc(*op, t),
        // UNOBSERVABLE placeholder (BEHAVIOR.md): not oracle-pinned.
        Term::PatMatch(inner) => beside_op(text("="), doc(inner)),
    }
}

/// Sigil + name + `.idx` suffix (suffix only when idx > 0).
fn var_str(v: &VarSpec) -> String {
    let sigil = match v.sort {
        SortHint::Msg | SortHint::Untagged | SortHint::Suffix(SuffixSort::Msg) => "",
        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => "$",
        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => "~",
        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => "#",
        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => "%",
    };
    if v.idx > 0 {
        format!("{sigil}{}.{}", v.name, v.idx)
    } else {
        format!("{sigil}{}", v.name)
    }
}

/// `f(a1, a2, …)`: commas attach to the preceding argument, fill space
/// between arguments (fsep), wrap aligns after the `(`, `)` attaches to the
/// last argument (probe:t_wide W2, probe:e_long).
fn app_doc(f: &str, args: &[Term]) -> Doc {
    let arg_docs = punctuate(&char(','), args.iter().map(doc).collect());
    beside_op(
        beside_op(text(&format!("{f}(")), fsep(arg_docs)),
        char(')'),
    )
}

/// `<a, b, c>`: `", "` attaches to each non-last element (fcat — a wrapped
/// line keeps the trailing space, probe:t_wide W1), `<`/`>` attach outside.
/// A Pair in LAST position flattens into the enclosing tuple; other positions
/// keep their own delimiters (probe:t_pair).
fn pair_doc(elems: &[Term]) -> Doc {
    let mut flat: Vec<&Term> = Vec::new();
    collect_pair(elems, &mut flat);
    let docs = punctuate(&text(", "), flat.into_iter().map(doc).collect());
    beside_op(beside_op(char('<'), fcat(docs)), char('>'))
}

fn collect_pair<'a>(elems: &'a [Term], out: &mut Vec<&'a Term>) {
    for (i, e) in elems.iter().enumerate() {
        match e {
            Term::Pair(inner) if i + 1 == elems.len() => collect_pair(inner, out),
            _ => out.push(e),
        }
    }
}

/// `a^b^c`: chains flatten for BOTH association orders (probe:t_exp2), the
/// `^` attaches to the preceding operand, no spaces, no parens added.
fn exp_doc(t: &Term) -> Doc {
    let mut leaves: Vec<&Term> = Vec::new();
    collect_exp(t, &mut leaves);
    let docs = punctuate(&char('^'), leaves.into_iter().map(doc).collect());
    fcat(docs)
}

fn collect_exp<'a>(t: &'a Term, out: &mut Vec<&'a Term>) {
    match t {
        Term::BinOp(BinOp::Exp, a, b) => {
            collect_exp(a, out);
            collect_exp(b, out);
        }
        Term::AlgApp(name, a, b) if name == "exp" => {
            collect_exp(a, out);
            collect_exp(b, out);
        }
        _ => out.push(t),
    }
}

/// AC operator: `(a<op>b<op>c)` — self-parenthesized, flattened across both
/// sides, operator attached to the preceding element, no spaces, fcat break
/// between elements (probes:t_xor, t_uni, t_nat, t_mult2, t_uniwide).
fn ac_doc(op: BinOp, t: &Term) -> Doc {
    let glyph = match op {
        BinOp::Mult => "*",
        BinOp::Union => "++",
        BinOp::Xor => "\u{2295}",
        BinOp::NatPlus => "%+",
        BinOp::Exp => unreachable!("Exp renders via exp_doc"),
    };
    let mut leaves: Vec<&Term> = Vec::new();
    collect_ac(op, t, &mut leaves);
    let docs = punctuate(&text(glyph), leaves.into_iter().map(doc).collect());
    beside_op(beside_op(char('('), fcat(docs)), char(')'))
}

fn collect_ac<'a>(op: BinOp, t: &'a Term, out: &mut Vec<&'a Term>) {
    match t {
        Term::BinOp(o, a, b) if *o == op => {
            collect_ac(op, a, out);
            collect_ac(op, b, out);
        }
        _ => out.push(t),
    }
}

//! R1 — signature block: `builtins:` / `functions:` / `equations:`.
//!
//! Renders the declared signature as the theory echo's first section,
//! performing the OBSERVABLE closure over builtins (all oracle-pinned; see
//! workspace/BEHAVIOR.md "Signature section" for probe provenance):
//!
//!   * only diffie-hellman / bilinear-pairing / multiset / natural-numbers /
//!     xor keep a `builtins:` entry, in exactly that canonical order;
//!     bilinear-pairing induces diffie-hellman; every other builtin expands
//!     into function/equation entries instead;
//!   * the base pairing symbols `fst/1, pair/2, snd/1` and the two projection
//!     equations are always present (`dest-pairing` flips fst/snd to
//!     `[destructor]`);
//!   * functions dedup and sort byte-wise; attributes render
//!     `[private,constructor]` / `[private,destructor]` / `[destructor]` /
//!     nothing;
//!   * equations dedup exactly and sort byte-wise on their rendered text;
//!   * layout: builtins and functions are `text prefix <> fsep` fill lines;
//!     the equations block is all-or-nothing — one line when it fits the
//!     73-column ribbon, otherwise one equation per line at indent 4; an
//!     overlong equation drops `= rhs` to (equation indent − 2).

use crate::ast::{Equation, FunctionDecl, Signature, SortHint, Term, VarSpec};
use crate::doc::{
    beside_op, char, fsep, nest, punctuate, render_with, sep, text, vcat, Doc,
};
use crate::term::{self, RIBBON, WIDTH};

/// Header comment above the declarations (byte-exact from every capture).
const HEADER: &str = "// Function signature and definition of the equational theory E";

/// Full signature section: header comment, blank line, then the declaration
/// lines (`builtins:` only when it has surviving entries).
pub fn render(sig: &Signature) -> String {
    render_with(WIDTH, RIBBON, &block_doc(sig))
}

pub(crate) fn block_doc(sig: &Signature) -> Doc {
    let mut lines = vec![text(HEADER), text("")];
    let builtin_names = builtins_line_entries(&sig.builtins);
    if !builtin_names.is_empty() {
        lines.push(fill_line(
            "builtins: ",
            builtin_names.iter().map(|n| text(n)).collect(),
        ));
    }
    lines.push(fill_line(
        "functions: ",
        merged_function_items(sig).iter().map(|s| text(s)).collect(),
    ));
    lines.push(equations_doc(sig));
    vcat(lines)
}

/// `text prefix <> fsep (punctuate ',' items)`: comma attached to the
/// preceding item, fill space between items, continuation aligned after the
/// prefix (probe:b_all, probe:b_revealing-signing).
fn fill_line(prefix: &str, items: Vec<Doc>) -> Doc {
    beside_op(text(prefix), fsep(punctuate(&char(','), items)))
}

// ── builtins line ───────────────────────────────────────────────────────────

/// The five builtins with a line entry, in canonical order (probe:b_all).
const LINE_ORDER: [&str; 5] = [
    "diffie-hellman",
    "bilinear-pairing",
    "multiset",
    "natural-numbers",
    "xor",
];

fn builtins_line_entries(declared: &[String]) -> Vec<&'static str> {
    let mut present = [false; 5];
    for b in declared {
        match b.as_str() {
            "diffie-hellman" => present[0] = true,
            // bilinear-pairing induces diffie-hellman (probe:b_bilinear-pairing).
            "bilinear-pairing" => {
                present[0] = true;
                present[1] = true;
            }
            "multiset" => present[2] = true,
            "natural-numbers" => present[3] = true,
            "xor" => present[4] = true,
            _ => {}
        }
    }
    LINE_ORDER
        .iter()
        .zip(present)
        .filter_map(|(n, p)| p.then_some(*n))
        .collect()
}

// ── functions line ──────────────────────────────────────────────────────────

fn decl(name: &str, arity: usize, private: bool, destructor: bool) -> FunctionDecl {
    FunctionDecl {
        name: name.into(),
        arity,
        private,
        destructor,
    }
}

/// `name/arity` + attribute suffix (probe:f_attrs): `private` implies a
/// role keyword is shown too; a public destructor shows `[destructor]` alone;
/// a public constructor shows nothing.
fn function_item(d: &FunctionDecl) -> String {
    let mut s = format!("{}/{}", d.name, d.arity);
    if d.private || d.destructor {
        let mut attrs: Vec<&str> = Vec::new();
        if d.private {
            attrs.push("private");
        }
        attrs.push(if d.destructor { "destructor" } else { "constructor" });
        s.push('[');
        s.push_str(&attrs.join(","));
        s.push(']');
    }
    s
}

/// Base + builtin-expansion + user function symbols, deduped and byte-sorted.
/// Sorting the full item text equals sorting by name (`/` orders below every
/// identifier character), matching probe:f_sort.
fn merged_function_items(sig: &Signature) -> Vec<String> {
    let mut decls: Vec<FunctionDecl> = base_functions(&sig.builtins);
    for b in &sig.builtins {
        decls.extend(builtin_functions(b));
    }
    decls.extend(sig.functions.iter().cloned());
    let mut items: Vec<String> = decls.iter().map(function_item).collect();
    items.sort();
    items.dedup();
    items
}

/// Always-present pairing symbols; `dest-pairing` flips the projections to
/// destructors (probe:b_none, probe:b_dest-pairing).
fn base_functions(declared: &[String]) -> Vec<FunctionDecl> {
    let dest = declared.iter().any(|b| b == "dest-pairing");
    vec![
        decl("fst", 1, false, dest),
        decl("pair", 2, false, false),
        decl("snd", 1, false, dest),
    ]
}

/// Function symbols induced by one declared builtin (probes:b_*; compatibility
/// content learned from oracle output).
fn builtin_functions(name: &str) -> Vec<FunctionDecl> {
    match name {
        "hashing" => vec![decl("h", 1, false, false)],
        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![
            decl("adec", 2, false, name.starts_with("dest-")),
            decl("aenc", 2, false, false),
            decl("pk", 1, false, false),
        ],
        "signing" | "dest-signing" => vec![
            decl("pk", 1, false, false),
            decl("sign", 2, false, false),
            decl("true", 0, false, false),
            decl("verify", 3, false, name.starts_with("dest-")),
        ],
        "symmetric-encryption" | "dest-symmetric-encryption" => vec![
            decl("sdec", 2, false, name.starts_with("dest-")),
            decl("senc", 2, false, false),
        ],
        "revealing-signing" => vec![
            decl("getMessage", 1, false, false),
            decl("pk", 1, false, false),
            decl("revealSign", 2, false, false),
            decl("revealVerify", 3, false, false),
            decl("true", 0, false, false),
        ],
        "locations-report" => vec![
            decl("check_rep", 2, false, true),
            decl("get_rep", 1, false, true),
            decl("rep", 2, true, false),
            decl("report", 1, false, false),
        ],
        _ => Vec::new(),
    }
}

// ── equations block ─────────────────────────────────────────────────────────

/// `sep (header : map (nest 4) (punctuate ',' eqs))`: one line when it fits,
/// otherwise header alone and one equation per line at indent 4
/// (probe:e_mid, probe:e_conv, target:Tutorial).
fn equations_doc(sig: &Signature) -> Doc {
    let header = if sig.convergent {
        "equations [convergent]:"
    } else {
        "equations:"
    };
    let eqs = merged_equations(sig);
    let mut elems = vec![text(header)];
    for d in punctuate(&char(','), eqs.iter().map(equation_doc).collect()) {
        elems.push(nest(4, &d));
    }
    sep(elems)
}

/// `sep [lhs, nest (-2) ("= " <> rhs)]`: one line `lhs = rhs`; an overlong
/// equation drops `= rhs` to (equation indent − 2) (probe:e_long).
fn equation_doc(eq: &Equation) -> Doc {
    sep(vec![
        term::doc(&eq.lhs),
        nest(-2, &beside_op(text("= "), term::doc(&eq.rhs))),
    ])
}

/// One-line text of an equation — the dedup/sort key (probe:e_adedup pins
/// byte order on this rendered text; probe:e_dup pins exact-dedup).
fn equation_key(eq: &Equation) -> String {
    render_with(isize::MAX / 2, isize::MAX / 2, &equation_doc(eq))
}

/// Base + builtin-expansion + user equations, deduped and byte-sorted on
/// their rendered text.
fn merged_equations(sig: &Signature) -> Vec<Equation> {
    let mut eqs = base_equations();
    for b in &sig.builtins {
        eqs.extend(builtin_equations(b));
    }
    eqs.extend(sig.equations.iter().cloned());
    let mut keyed: Vec<(String, Equation)> =
        eqs.into_iter().map(|e| (equation_key(&e), e)).collect();
    keyed.sort_by(|a, b| a.0.cmp(&b.0));
    keyed.dedup_by(|a, b| a.0 == b.0);
    keyed.into_iter().map(|(_, e)| e).collect()
}

/// `x.<i>` — the variable spelling in builtin-induced equations
/// (probe:b_none and every builtin expansion probe).
fn xv(i: u64) -> Term {
    Term::Var(VarSpec {
        name: "x".into(),
        idx: i,
        sort: SortHint::Untagged,
        typ: None,
    })
}

fn app(f: &str, args: Vec<Term>) -> Term {
    Term::App(f.into(), args)
}

fn eq(lhs: Term, rhs: Term) -> Equation {
    Equation { lhs, rhs }
}

/// `fst(<x.1, x.2>) = x.1`, `snd(<x.1, x.2>) = x.2` (probe:b_none).
fn base_equations() -> Vec<Equation> {
    vec![
        eq(app("fst", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(1)),
        eq(app("snd", vec![Term::Pair(vec![xv(1), xv(2)])]), xv(2)),
    ]
}

/// Equations induced by one declared builtin (probes:b_*).
fn builtin_equations(name: &str) -> Vec<Equation> {
    match name {
        // adec(aenc(x.1, pk(x.2)), x.2) = x.1
        "asymmetric-encryption" | "dest-asymmetric-encryption" => vec![eq(
            app(
                "adec",
                vec![
                    app("aenc", vec![xv(1), app("pk", vec![xv(2)])]),
                    xv(2),
                ],
            ),
            xv(1),
        )],
        // verify(sign(x.1, x.2), x.1, pk(x.2)) = true
        "signing" | "dest-signing" => vec![eq(
            app(
                "verify",
                vec![
                    app("sign", vec![xv(1), xv(2)]),
                    xv(1),
                    app("pk", vec![xv(2)]),
                ],
            ),
            app("true", vec![]),
        )],
        // sdec(senc(x.1, x.2), x.2) = x.1
        "symmetric-encryption" | "dest-symmetric-encryption" => vec![eq(
            app(
                "sdec",
                vec![app("senc", vec![xv(1), xv(2)]), xv(2)],
            ),
            xv(1),
        )],
        // getMessage(revealSign(x.1, x.2)) = x.1
        // revealVerify(revealSign(x.1, x.2), x.1, pk(x.2)) = true
        "revealing-signing" => vec![
            eq(
                app("getMessage", vec![app("revealSign", vec![xv(1), xv(2)])]),
                xv(1),
            ),
            eq(
                app(
                    "revealVerify",
                    vec![
                        app("revealSign", vec![xv(1), xv(2)]),
                        xv(1),
                        app("pk", vec![xv(2)]),
                    ],
                ),
                app("true", vec![]),
            ),
        ],
        // check_rep(rep(x.1, x.2), x.2) = x.1 ; get_rep(rep(x.1, x.2)) = x.1
        "locations-report" => vec![
            eq(
                app(
                    "check_rep",
                    vec![app("rep", vec![xv(1), xv(2)]), xv(2)],
                ),
                xv(1),
            ),
            eq(app("get_rep", vec![app("rep", vec![xv(1), xv(2)])]), xv(1)),
        ],
        _ => Vec::new(),
    }
}

